const transactions = $json.body.transactions ?? [];

// Define your type families
const TRIAL_TYPES = new Set(['trial', 'split_trial', 'no_split_trial']);
const UPSELL_TYPES = new Set(['upsell']);
const RECURRENT_TYPES = new Set(['recurrent']);

// Optional: treat unknown types explicitly
// If you want unknown types to push the user into an "OTHER/UNKNOWN" bucket,
// keep this flag true and see the logic below.
const FLAG_UNKNOWN_TYPES = true;

let hasTrial = false;
let hasUpsell = false;
let hasRecurrent = false;

const unknownTypes = new Set();

// Scan transactions once
for (const t of transactions) {
  const type = String(t?.type ?? '').trim();

  if (TRIAL_TYPES.has(type)) hasTrial = true;
  else if (UPSELL_TYPES.has(type)) hasUpsell = true;
  else if (RECURRENT_TYPES.has(type)) hasRecurrent = true;
  else if (type) unknownTypes.add(type);
  else unknownTypes.add('(missing_type)');
}

// Decide category based on which families are present
// Unique outputs for easy filtering:
let category;

// If you want to handle empty transactions specially:
if (transactions.length === 0) {
  category = 'CAT__NO_TRANSACTIONS';
} else if (FLAG_UNKNOWN_TYPES && unknownTypes.size > 0) {
  category = 'CAT__UNKNOWN_TYPE_PRESENT';
} else if (hasTrial && !hasUpsell && !hasRecurrent) {
  category = 'CAT__TRIAL_ONLY';
} else if (!hasTrial && hasUpsell && !hasRecurrent) {
  category = 'CAT__UPSELL_ONLY';
} else if (!hasTrial && !hasUpsell && hasRecurrent) {
  category = 'CAT__RECURRENT_ONLY';
} else if (hasTrial && !hasUpsell && hasRecurrent) {
  category = 'CAT__RECURRENT_AND_TRIAL';
} else if (!hasTrial && hasUpsell && hasRecurrent) {
  category = 'CAT__RECURRENT_AND_UPSELL';
} else if (hasTrial && hasUpsell && !hasRecurrent) {
  category = 'CAT__UPSELL_AND_TRIAL';
} else if (hasTrial && hasUpsell && hasRecurrent) {
  category = 'CAT__ALL_THREE_PRESENT';
} else {
  // Fallback (should be rare if the above is exhaustive)
  category = 'CAT__UNCLASSIFIED';
}

return [
  {
    json: {
      ...$json,
      transactionCategory: category,

      // Helpful debug fields (you can remove these later)
      categoryFlags: {
        hasTrial,
        hasUpsell,
        hasRecurrent,
      },
      unknownTypes: Array.from(unknownTypes),
    },
  },
];

