// 🔧 Change this to the word you want to search for
const SEARCH_WORD = "trial";

const inputItem = $input.first().json;
const transactions = Array.isArray(inputItem.body?.transactions)
  ? inputItem.body.transactions
  : [];

// Normalize search word (case-insensitive)
const normalizedSearch = SEARCH_WORD.toLowerCase();

// Filter transactions containing the word in ANY field
const filteredTransactions = transactions.filter(transaction => {
  if (!transaction || typeof transaction !== "object") return false;

  return Object.values(transaction).some(value => {
    if (value === null || value === undefined) return false;
    return String(value).toLowerCase().includes(normalizedSearch);
  });
});

// Always return a single item
if (filteredTransactions.length === 0) {
  return [
    {
      json: {
        noMatchingTransactions: true,
        searchWord: SEARCH_WORD,
        transactions: []
      }
    }
  ];
}

return [
  {
    json: {
      searchWord: SEARCH_WORD,
      transactions: filteredTransactions
    }
  }
];

